#include <windows.h>
#include <userint.h>
#include <utility.h>
#include <ansi_c.h>
#include <cvirte.h>
#include "tnt_exec.h"

int __stdcall WinMain(HINSTANCE hInstance, HINSTANCE hPrevInstance, LPSTR lpszCmdLine, int nCmdShow)
{
    if (InitCVIRTE(hInstance, 0, 0) == 0)
    {
        return -1;
    }

    exec_Start(WIN_MAIN, NULL, lpszCmdLine);
    return 0;
}

int Init(void)
{
    /* Initialize instrumentation, logging and bench state here. */
    exec_Init_SQL_Logging(TNT_LOGGING, "", "", "", 20, 9, 1, ALL_RESULT_ON_ONE_LINE, 30, 1, "");
    return 0;
}

int Begin(void)
{
    char serialNumber[50] = {0};

    PromptPopup("Start test", "Enter UUT serial number", serialNumber, sizeof(serialNumber) - 1);
    exec_Serial_Nb(serialNumber, 1);
    exec_Return_String(serialNumber, "NUMERO DE SERIE", "serial");
    return 0;
}

int End(void)
{
    return 0;
}

int Abort(void)
{
    return 0;
}

int Stop(void)
{
    return 0;
}

int MyTest(void)
{
    int code = 0;
    short status = 0;
    short success = TEST_PASS;
    double value = 0.0;

    code = exec_Get_Parameter("#HighLimit", &value);
    exec_Error(TNT_NONE, "MyTest => read #HighLimit", code, &status);

    if (!status)
    {
        code = exec_Return_Meas(1, value, 4, 0.0, 5.0, "V", "Voltage check", "VOLTAGE", &success);
        exec_Error(TNT_NONE, "MyTest => return voltage measurement", code, &status);
    }

    return status;
}

int Autofunc(short Etat_Global)
{
    /* Etat_Global is a sequencer bit field: idle, development mode, break modes, ticket/log state, etc. */
    if (Etat_Global & (1 << 6))
    {
        /* Program idle after Load / Init / End / Halt / Abort. */
    }

    return 0; /* or AUTORUN_RUN_PROG, AUTORUN_RUN_INIT, AUTORUN_ABORT, AUTORUN_HALT, AUTORUN_OPEN_PROG */
}

int code = 0;
short status = 0;
int *maxNbModule = NULL;
int *indexMd = NULL;
int *statusMd = NULL;
int *nbFailMd = NULL;

