                         "Module loop", "Select modules", "Module results", "Result per module");
exec_Error(TNT_NONE, "Init => exec_Init_Loop_Md", code, &status);

if (!status)
{
    code = exec_Get_Loop_Md_Parameters(&maxNbModule, &indexMd, &statusMd, &nbFailMd);
